import cv2from matplotlib import pyplot as pltimport numpy as npimg = cv2.imread("../data/BSE_Google.jpg", 0)median = cv2.medianBlur(img,3)plt.figure(figsize = (16,8))plt.subplot(2,2,1)plt.imshow(img, cmap = "gray")plt.title("Original Image")plt.subplot(2,2,2)plt.hist(img.flat, bins =100, range = (0, 255))plt.title("Histogram")ret, thresh1 = cv2.threshold(median, 0, 255, cv2.THRESH_BINARY+cv2.THRESH_OTSU)plt.subplot(2,2,3)plt.imshow(thresh1, cmap='gray')plt.title("Threshold Image")kernel = np.ones((3,3), np.uint8)plt.figure(figsize = (16,8))plt.subplot(2,2,1)plt.imshow(img, cmap = "gray")plt.title("Original Image")# print(kernel)erosion = cv2.erode(thresh1, kernel, iterations=1)plt.subplot(2,2,2)plt.imshow(erosion, cmap = 'gray')plt.title("After Erosion")"""Shrinks white regions.Effects:removes small white noiseseparates connected objects"""dilation = cv2.dilate(erosion, kernel, iterations =2)plt.subplot(2,2,3)plt.imshow(dilation, cmap = 'gray')plt.title("Dilation")"""Expands white regions.Effects:fills gapsreconnects broken regions"""opening = cv2.morphologyEx(thresh1, cv2.MORPH_OPEN, kernel)plt.subplot(2,2,4)plt.imshow(opening, cmap = 'gray')plt.title("Opening")"""Opening = Erosion + DilationPurpose:removes small white noisepreserves larger objectsClosing = Dilation + ErosionPurpose:fills small black holesconnects nearby regionstophat = cv2.morphologyEx(img, cv2.MORPH_TOPHAT, kernel)Top Hat = Original - OpeningExtracts small bright objects.blackhat = cv2.morphologyEx(img, cv2.MORPH_BLACKHAT, kernel)Black Hat = Closing - OriginalExtracts small dark objects."""